                      "type": "string",
                      "enum": ["string", "number", "boolean", "choice"],
                      "description": "Type of the sub-property."
                    },
                    "options": {
                      "type": "array",
                      "items": {
                        "type": "string"
                      }
                    }
                  },
                  "additionalProperties": false
                }
              }
            },
            "additionalProperties": false
          }
        ]
      },
      "examples": [
