          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Arguments for command or container execution"
        },
        "entrypoint": {
          "type": "string",
          "description": "Optional entrypoint override for container (equivalent to docker run --entrypoint)",
          "examples": ["/bin/sh", "/custom/entrypoint.sh", "python"]
        },
        "entrypointArgs": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Arguments to add after the container image (container entrypoint arguments)"
        },
        "mounts": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[^:]+:[^:]+:(ro|rw)$"
          },
          "description": "Volume mounts for container in format 'source:dest:mode' where mode is 'ro' or 'rw'",
          "examples": [["/tmp/data:/data:ro"], ["/workspace:/workspace:rw", "/config:/config:ro"]]
        },
        "env": {
          "type": "object",
          "patternProperties": {
            "^[A-Z_][A-Z0-9_]*$": {
              "type": "string"
            }
          },
          "additionalProperties": false,
          "description": "Environment variables for MCP server"
        },
        "network": {
          "type": "object",
          "deprecated": true,
          "$comment": "DEPRECATED: Per-server network configuration is no longer supported. Use top-level workflow 'network:' configuration instead.",
          "properties": {
            "allowed": {
              "type": "array",
              "items": {
                "type": "string",
                "pattern": "^[a-zA-Z0-9]([a-zA-Z0-9\\-]{0,61}[a-zA-Z0-9])?(\\.[a-zA-Z0-9]([a-zA-Z0-9\\-]{0,61}[a-zA-Z0-9])?)*$",
                "description": "Allowed domain name"
              },
              "minItems": 1,
              "uniqueItems": true,
              "description": "List of allowed domain names for network access",
              "maxItems": 100
            },
            "proxy-args": {
              "type": "array",
              "items": {
                "type": "string"
              },
              "description": "Custom proxy arguments for container-based MCP servers"
            }
          },
          "additionalProperties": false,
          "description": "DEPRECATED: Per-server network configuration is no longer supported. Use top-level workflow 'network:' configuration instead. This field is ignored and will be removed in a future version."
        },
        "allowed": {
          "type": "array",
          "description": "List of allowed tool names for this MCP server",
          "items": {
            "type": "string"
          },
          "examples": [["*"], ["store_memory", "retrieve_memory"], ["brave_web_search"]]
        }
      },
      "additionalProperties": false,
      "$comment": "Validation constraints: (1) Mutual exclusion: 'command' and 'container' cannot both be specified. (2) Requirement: Either 'command' or 'container' must be provided (via 'anyOf'). (3) Type constraint: When 'type' is 'stdio' or 'local', either 'command' or 'container' is required. Note: Per-server 'network' field is deprecated and ignored.",
      "anyOf": [
        {
          "required": ["type"]
        },
        {
          "required": ["command"]
        },
        {
          "required": ["container"]
        }
      ],
      "not": {
        "allOf": [
          {
            "required": ["command"]
          },
          {
            "required": ["container"]
          }
        ]
      },
      "allOf": [
        {
          "if": {
            "properties": {
              "type": {
                "enum": ["stdio", "local"]
              }
            }
          },
          "then": {
            "anyOf": [
              {
                "required": ["command"]
              },
              {
                "required": ["container"]
              }
            ]
          }
        }
      ]
    },
    "http_mcp_tool": {
      "type": "object",
      "description": "HTTP MCP tool configuration",
      "properties": {
        "type": {
          "type": "string",
          "enum": ["http"],
          "description": "MCP connection type for HTTP"
        },
        "registry": {
          "type": "string",
          "description": "URI to the installation location when MCP is installed from a registry",
          "examples": ["https://api.mcp.github.com/v0/servers/microsoft/markitdown"]
        },
        "url": {
          "type": "string",
          "minLength": 1,
          "description": "URL for HTTP MCP connections"
        },
        "headers": {
          "type": "object",
          "patternProperties": {
            "^[A-Za-z0-9_-]+$": {
              "type": "string"
            }
          },
          "additionalProperties": false,
          "description": "HTTP headers for HTTP MCP connections"
        },
        "allowed": {
          "type": "array",
          "description": "List of allowed tool names for this MCP server",
          "items": {
            "type": "string"
          },
          "examples": [["*"], ["store_memory", "retrieve_memory"], ["brave_web_search"]]
        }
      },
      "required": ["url"],
      "additionalProperties": false
    },
    "github_token": {
      "type": "string",
      "pattern": "^\\$\\{\\{\\s*secrets\\.[A-Za-z_][A-Za-z0-9_]*(\\s*\\|\\|\\s*secrets\\.[A-Za-z_][A-Za-z0-9_]*)*\\s*\\}\\}$",
      "description": "GitHub token expression using secrets. Pattern details: `[A-Za-z_][A-Za-z0-9_]*` matches a valid secret name (starts with a letter or underscore, followed by letters, digits, or underscores). The full pattern matches expressions like `${{ secrets.NAME }}` or `${{ secrets.NAME1 || secrets.NAME2 }}`.",
      "examples": ["${{ secrets.GITHUB_TOKEN }}", "${{ secrets.CUSTOM_PAT }}", "${{ secrets.GH_AW_GITHUB_TOKEN || secrets.GITHUB_TOKEN }}"]
    },
    "github_app": {
      "type": "object",
      "description": "GitHub App credentials for minting installation access tokens.",
      "properties": {
        "app-id": {
          "type": "string",
          "description": "GitHub App ID (e.g., '${{ vars.APP_ID }}'). Required to mint a GitHub App token.",
          "examples": ["${{ vars.APP_ID }}"]
        },
        "private-key": {
          "type": "string",
          "description": "GitHub App private key (e.g., '${{ secrets.APP_PRIVATE_KEY }}'). Required to mint a GitHub App token.",
          "examples": ["${{ secrets.APP_PRIVATE_KEY }}"]
        },
        "owner": {
          "type": "string",
          "description": "Optional owner of the GitHub App installation (defaults to current repository owner if not specified)"
        },
        "repositories": {
          "type": "array",
          "description": "Optional list of repositories to grant access to (defaults to current repository if not specified)",
          "items": {
            "type": "string"
          }
        },
        "permissions": {
          "$ref": "#/$defs/github_app_permissions",
          "description": "Optional extra GitHub App-only permissions to merge into the minted token. Only takes effect for tools.github.github-app; ignored in other github-app contexts."
        }
      },
      "required": ["app-id", "private-key"],
      "additionalProperties": false,
      "examples": [
        {
          "app-id": "${{ vars.APP_ID }}",
          "private-key": "${{ secrets.APP_PRIVATE_KEY }}"
        }
      ]
    },
    "githubActionsStep": {
      "type": "object",
