          "examples": [["**/node_modules/**", "**/*.test.md"]]
        },
        "context": {
          "type": "string",
          "description": "Optional context injected into the qmd collection, providing the agent with additional hints about the content (e.g. 'GitHub Actions documentation')."
        },
        "checkout": {
