      "examples": ["workflow-2024-q1", "team-alpha-bot", "security_audit_v2"]
    },
    "labels": {
      "type": "array",
      "description": "Optional array of labels to categorize and organize workflows. Labels can be used to filter workflows in status/list commands.",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "examples": [
        ["automation", "security"],
        ["docs", "maintenance"],
        ["ci", "testing"]
      ]
    },
    "metadata": {
      "type": "object",
      "description": "Optional metadata field for storing custom key-value pairs compatible with the custom agent spec. Key names are limited to 64 characters, and values are limited to 1024 characters.",
      "patternProperties": {
        "^.{1,64}$": {
          "type": "string",
          "maxLength": 1024,
          "description": "Metadata value (maximum 1024 characters)"
        }
      },
      "additionalProperties": false,
      "examples": [
        {
          "author": "John Doe",
          "version": "1.0.0",
          "category": "automation"
        }
      ]
    },
    "imports": {
      "description": "Workflow specifications to import. Supports array form (list of paths) or object form with 'aw' (agentic workflow paths) and 'apm-packages' (APM packages) subfields.",
      "oneOf": [
        {
          "type": "array",
          "description": "Array of workflow specifications to import (similar to @include directives but defined in frontmatter). Format: owner/repo/path@ref (e.g., githubnext/agentics/workflows/shared/common.md@v1.0.0). Can be strings or objects with path and inputs. Any markdown files under .github/agents directory are treated as custom agent files and only one agent file is allowed per workflow.",
          "items": {
            "oneOf": [
              {
                "type": "string",
                "description": "Workflow specification in format owner/repo/path@ref. Markdown files under .github/agents/ are treated as agent configuration files."
              },
              {
                "type": "object",
                "description": "Import specification with path and optional inputs",
                "required": ["path"],
                "additionalProperties": false,
                "properties": {
                  "path": {
                    "type": "string",
                    "description": "Workflow specification in format owner/repo/path@ref. Markdown files under .github/agents/ are treated as agent configuration files."
                  },
                  "inputs": {
                    "type": "object",
                    "description": "Input values to pass to the imported workflow. Keys are input names declared in the imported workflow's inputs section, values can be strings or expressions.",
                    "additionalProperties": {
                      "oneOf": [
                        {
                          "type": "string"
                        },
                        {
                          "type": "number"
                        },
                        {
                          "type": "boolean"
                        },
                        {
                          "type": "object",
                          "description": "Object value for import-schema parameters of type 'object' (one level deep).",
                          "additionalProperties": {
                            "oneOf": [
                              {
                                "type": "string"
                              },
                              {
                                "type": "number"
                              },
                              {
                                "type": "boolean"
                              }
                            ]
                          }
                        }
                      ]
                    }
                  }
                }
              },
              {
                "type": "object",
                "description": "Import specification with 'uses'/'with' syntax (mirrors GitHub Actions reusable workflow syntax). 'uses' references the workflow path and 'with' provides input values.",
                "required": ["uses"],
                "additionalProperties": false,
                "properties": {
                  "uses": {
                    "type": "string",
                    "description": "Workflow specification in format owner/repo/path@ref. Alias for 'path'."
                  },
