        "mentions": {
          "description": "Configuration for @mention filtering in safe outputs. Controls whether and how @mentions in AI-generated content are allowed or escaped.",
          "oneOf": [
            {
              "type": "boolean",
              "description": "Simple boolean mode: false = always escape mentions, true = always allow mentions (error in strict mode)"
            },
            {
              "type": "object",
              "description": "Advanced configuration for @mention filtering with fine-grained control",
              "properties": {
                "allow-team-members": {
                  "type": "boolean",
                  "description": "Allow mentions of repository team members (collaborators with any permission level, excluding bots). Default: true",
                  "default": true
                },
                "allow-context": {
                  "type": "boolean",
                  "description": "Allow mentions inferred from event context (issue/PR authors, assignees, commenters). Default: true",
                  "default": true
                },
                "allowed": {
                  "type": "array",
                  "description": "List of user/bot names always allowed to be mentioned. Bots are not allowed by default unless listed here.",
                  "items": {
                    "type": "string",
                    "minLength": 1
                  }
                },
                "max": {
                  "description": "Maximum number of mentions allowed per message. Default: 50 Supports integer or GitHub Actions expression (e.g. '${{ inputs.max }}').",
                  "oneOf": [
                    {
                      "type": "integer",
                      "minimum": 1,
                      "default": 50
                    },
                    {
                      "type": "string",
                      "pattern": "^\\$\\{\\{.*\\}\\}$",
                      "description": "GitHub Actions expression that resolves to an integer at runtime"
                    }
                  ]
                }
              },
              "additionalProperties": false
            }
          ]
        },
        "footer": {
          "type": "boolean",
          "description": "Global footer control for all safe outputs. When false, omits visible AI-generated footer content from all created/updated entities (issues, PRs, discussions, releases) while still including XML markers for searchability. Individual safe-output types (create-issue, update-issue, etc.) can override this by specifying their own footer field. Defaults to true.",
          "default": true,
          "examples": [false, true]
        },
        "activation-comments": {
          "type": ["boolean", "string"],
          "description": "When set to false or \"false\", disables all activation and fallback comments entirely (run-started, run-success, run-failure, PR/issue creation links). Supports templatable boolean values including GitHub Actions expressions (e.g. ${{ inputs.activation-comments }}). Default: true",
          "default": true,
          "examples": [false, true, "${{ inputs.activation-comments }}"]
        },
        "group-reports": {
          "type": "boolean",
          "description": "When true, creates a parent '[aw] Failed runs' issue that tracks all workflow failures as sub-issues. Helps organize failure tracking but may be unnecessary in smaller repositories. Defaults to false.",
          "default": false,
          "examples": [false, true]
        },
        "report-failure-as-issue": {
          "type": "boolean",
          "description": "When false, disables creating failure tracking issues when workflows fail. Useful for workflows where failures are expected or handled elsewhere. Defaults to true.",
          "default": true,
          "examples": [false, true]
        },
        "failure-issue-repo": {
          "type": "string",
          "description": "Repository to create failure tracking issues in, in the format 'owner/repo'. Useful when the current repository has issues disabled. Defaults to the current repository.",
          "pattern": "^[^/]+/[^/]+$",
          "examples": ["github/docs-engineering", "myorg/infra-alerts"]
        },
        "max-bot-mentions": {
          "description": "Maximum number of bot trigger references (e.g. 'fixes #123', 'closes #456') allowed in output before all of them are neutralized. Default: 10. Supports integer or GitHub Actions expression (e.g. '${{ inputs.max-bot-mentions }}').",
          "oneOf": [
            {
              "type": "integer",
              "minimum": 1,
              "default": 10
            },
            {
              "type": "string",
              "pattern": "^\\$\\{\\{.*\\}\\}$",
              "description": "GitHub Actions expression that resolves to an integer at runtime"
            }
          ]
        },
        "id-token": {
          "type": "string",
          "enum": ["write", "none"],
          "description": "Override the id-token permission for the safe-outputs job. Use 'write' to force-enable the id-token: write permission (required for OIDC authentication with cloud providers). Use 'none' to suppress automatic detection and prevent adding id-token: write even when vault/OIDC actions are detected in steps. By default, the compiler auto-detects known OIDC/vault actions (aws-actions/configure-aws-credentials, azure/login, google-github-actions/auth, hashicorp/vault-action, cyberark/conjur-action) and adds id-token: write automatically.",
          "examples": ["write", "none"]
        },
        "concurrency-group": {
          "type": "string",
          "description": "Concurrency group for the safe-outputs job. When set, the safe-outputs job will use this concurrency group with cancel-in-progress: false. Supports GitHub Actions expressions.",
          "examples": ["my-workflow-safe-outputs", "safe-outputs-${{ github.repository }}"]
        },
        "environment": {
          "description": "Override the GitHub deployment environment for the safe-outputs job. When set, this environment is used instead of the top-level environment: field. When not set, the top-level environment: field is propagated automatically so that environment-scoped secrets are accessible in the safe-outputs job.",
          "oneOf": [
            {
              "type": "string",
              "description": "Environment name as a string"
            },
            {
              "type": "object",
              "description": "Environment object with name and optional URL",
              "properties": {
                "name": {
                  "type": "string",
                  "description": "The name of the environment configured in the repo"
                },
                "url": {
                  "type": "string",
                  "description": "A deployment URL"
                }
              },
              "required": ["name"],
              "additionalProperties": false
            }
          ]
        },
        "runs-on": {
          "type": "string",
          "description": "Runner specification for all safe-outputs jobs (activation, create-issue, add-comment, etc.). Single runner label (e.g., 'ubuntu-slim', 'ubuntu-latest', 'windows-latest', 'self-hosted'). Defaults to 'ubuntu-slim'. See https://github.blog/changelog/2025-10-28-1-vcpu-linux-runner-now-available-in-github-actions-in-public-preview/"
        },
        "steps": {
          "type": "array",
          "description": "Custom steps to inject into all safe-output jobs. These steps run after checking out the repository and setting up the action, and before any safe-output code executes.",
          "items": {
            "$ref": "#/$defs/githubActionsStep"
          },
          "examples": [
            [
              {
                "name": "Install custom dependencies",
                "run": "npm install my-package"
              }
            ]
          ]
        },
        "actions": {
          "type": "object",
          "description": "Custom GitHub Actions to mount as once-callable MCP tools. Each action is resolved at compile time to derive its input schema from action.yml, and a guarded `uses:` step is injected in the safe_outputs job. Action names containing dashes will be automatically normalized to underscores (e.g., 'add-smoked-label' becomes 'add_smoked_label').",
          "patternProperties": {
            "^[a-zA-Z_][a-zA-Z0-9_-]*$": {
              "type": "object",
              "description": "Configuration for a custom safe output action.",
              "properties": {
                "uses": {
                  "type": "string",
                  "description": "The GitHub Action to use. Supports owner/repo@ref, owner/repo/subdir@ref, or ./local/path.",
                  "examples": ["actions-ecosystem/action-add-labels@v1", "owner/repo@v1", "owner/repo/subdir@v1"]
                },
                "description": {
                  "type": "string",
                  "description": "Optional description override for the MCP tool. Defaults to the action's description from action.yml."
                },
                "env": {
                  "type": "object",
                  "description": "Additional environment variables to set on the injected action step. Useful for passing secrets like GITHUB_TOKEN.",
                  "additionalProperties": {
                    "type": "string"
                  },
                  "examples": [
                    {
                      "GITHUB_TOKEN": "${{ github.token }}"
                    }
                  ]
                },
                "inputs": {
                  "type": "object",
                  "description": "Explicit input definitions for the action, overriding the auto-fetched action.yml schema. Use this to ensure deterministic compilation without requiring network access at compile time.",
                  "patternProperties": {
                    "^[a-zA-Z_][a-zA-Z0-9_-]*$": {
                      "type": "object",
                      "description": "Definition for a single action input.",
                      "properties": {
                        "description": {
                          "type": "string",
                          "description": "Description of the input."
                        },
                        "required": {
                          "type": "boolean",
                          "description": "Whether the input is required."
                        },
                        "default": {
                          "type": "string",
                          "description": "Default value for the input."
                        }
                      },
                      "additionalProperties": false
                    }
                  },
                  "additionalProperties": false
                }
              },
              "required": ["uses"],
              "additionalProperties": false
            }
          }
        }
      },
      "additionalProperties": false
    },
    "secret-masking": {
      "type": "object",
      "description": "Configuration for secret redaction behavior in workflow outputs and artifacts",
      "properties": {
        "steps": {
          "type": "array",
          "description": "Additional secret redaction steps to inject after the built-in secret redaction. Use this to mask secrets in generated files using custom patterns.",
          "items": {
            "$ref": "#/$defs/githubActionsStep"
          },
          "examples": [
            [
              {
                "name": "Redact custom secrets",
                "run": "find /tmp/gh-aw -type f -exec sed -i 's/password123/REDACTED/g' {} +"
              }
            ]
          ]
        }
      },
      "additionalProperties": false
    },
    "observability": {
      "type": "object",
      "description": "Optional observability output settings for workflow runs.",
      "properties": {
        "job-summary": {
          "type": "string",
          "enum": ["on", "off"],
          "description": "If set to 'on', append a compact observability section to the GitHub Actions job summary. Defaults to off when omitted."
        }
      },
      "additionalProperties": false
    },
    "bots": {
      "type": "array",
      "description": "Allow list of bot identifiers that can trigger the workflow even if they don't meet the required role permissions. When the actor is in this list, the bot must be active (installed) on the repository to trigger the workflow.",
      "items": {
        "type": "string",
        "minLength": 1,
        "pattern": "^[A-Za-z0-9._\\[\\]-]+$",
        "description": "Bot identifier/name (e.g., 'dependabot[bot]', 'renovate[bot]', 'github-actions[bot]')"
      }
    },
    "rate-limit": {
      "type": "object",
      "description": "Rate limiting configuration to restrict how frequently users can trigger the workflow. Helps prevent abuse and resource exhaustion from programmatically triggered events.",
      "required": ["max"],
      "properties": {
        "max": {
          "description": "Maximum number of workflow runs allowed per user within the time window. Required field. Supports integer or GitHub Actions expression (e.g. '${{ inputs.max }}').",
          "oneOf": [
            {
              "type": "integer",
              "minimum": 1,
              "maximum": 10
            },
            {
              "type": "string",
              "pattern": "^\\$\\{\\{.*\\}\\}$",
              "description": "GitHub Actions expression that resolves to an integer at runtime"
            }
          ]
        },
        "window": {
          "type": "integer",
          "minimum": 1,
          "maximum": 180,
          "default": 60,
          "description": "Time window in minutes for rate limiting. Defaults to 60 (1 hour). Maximum: 180 (3 hours)."
        },
        "events": {
          "type": "array",
          "description": "Optional list of event types to apply rate limiting to. If not specified, rate limiting applies to all programmatically triggered events (e.g., workflow_dispatch, issue_comment, pull_request_review).",
          "items": {
            "type": "string",
            "enum": ["workflow_dispatch", "issue_comment", "pull_request_review", "pull_request_review_comment", "issues", "pull_request", "discussion_comment", "discussion"]
          },
          "minItems": 1
        },
        "ignored-roles": {
          "type": "array",
          "description": "Optional list of roles that are exempt from rate limiting. Defaults to ['admin', 'maintain', 'write'] if not specified. Users with any of these roles will not be subject to rate limiting checks. To apply rate limiting to all users, set to an empty array: []",
          "items": {
            "type": "string",
            "enum": ["admin", "maintain", "write", "triage", "read"]
          },
          "minItems": 0
        }
      },
      "additionalProperties": false,
      "examples": [
        {
          "max": 5,
          "window": 60
        },
        {
          "max": 10,
          "window": 30,
          "events": ["workflow_dispatch", "issue_comment"]
        },
        {
          "max": 5,
          "window": 60,
          "ignored-roles": ["admin", "maintain"]
        }
      ]
    },
    "strict": {
      "type": "boolean",
      "default": true,
      "$comment": "Strict mode enforces several security constraints that are validated in Go code (pkg/workflow/strict_mode_validation.go) rather than JSON Schema: (1) Write Permissions + Safe Outputs: When strict=true AND permissions contains write values (contents:write, issues:write, pull-requests:write), safe-outputs must be configured. This relationship is too complex for JSON Schema as it requires checking if ANY permission property has a 'write' value. (2) Network Requirements: When strict=true, the 'network' field must be present and cannot contain standalone wildcard '*' (but patterns like '*.example.com' ARE allowed). (3) MCP Container Network: Custom MCP servers with containers require explicit network configuration. (4) Action Pinning: Actions must be pinned to commit SHAs. These are enforced during compilation via validateStrictMode().",
      "description": "Enable strict mode validation for enhanced security and compliance. Strict mode enforces: (1) Write Permissions - refuses contents:write, issues:write, pull-requests:write; requires safe-outputs instead, (2) Network Configuration - requires explicit network configuration with no standalone wildcard '*' in allowed domains (patterns like '*.example.com' are allowed), (3) Action Pinning - enforces actions pinned to commit SHAs instead of tags/branches, (4) MCP Network - requires network configuration for custom MCP servers with containers, (5) Deprecated Fields - refuses deprecated frontmatter fields. Can be enabled per-workflow via 'strict: true' in frontmatter, or disabled via 'strict: false'. CLI flag takes precedence over frontmatter (gh aw compile --strict enforces strict mode). Defaults to true. See: https://github.github.com/gh-aw/reference/frontmatter/#strict-mode-strict",
      "examples": [true, false]
    },
    "private": {
      "type": "boolean",
      "default": false,
      "description": "Mark the workflow as private, preventing it from being added to other repositories via 'gh aw add'. A workflow with private: true is not meant to be shared outside its repository.",
      "examples": [true, false]
    },
    "check-for-updates": {
      "type": "boolean",
      "default": true,
      "description": "Control whether the compile-agentic version update check runs in the activation job. When true (default), the activation job downloads config.json from the gh-aw repository and verifies the compiled version is not blocked and meets the minimum supported version. Set to false to disable the check (not allowed in strict mode). See: https://github.github.com/gh-aw/reference/frontmatter/#check-for-updates",
      "examples": [true, false]
    },
    "mcp-scripts": {
      "type": "object",
      "description": "MCP Scripts configuration for defining custom lightweight MCP tools as JavaScript, shell scripts, or Python scripts. Tools are mounted in an MCP server and have access to secrets specified by the user. Only one of 'script' (JavaScript), 'run' (shell), or 'py' (Python) must be specified per tool.",
      "patternProperties": {
        "^([a-ln-z][a-z0-9_-]*|m[a-np-z][a-z0-9_-]*|mo[a-ce-z][a-z0-9_-]*|mod[a-df-z][a-z0-9_-]*|mode[a-z0-9_-]+)$": {
          "type": "object",
          "description": "Custom tool definition. The key is the tool name (lowercase alphanumeric with dashes/underscores).",
          "required": ["description"],
          "properties": {
            "description": {
              "type": "string",
              "description": "Tool description that explains what the tool does. This is required and will be shown to the AI agent."
            },
            "inputs": {
              "type": "object",
              "description": "Optional input parameters for the tool using workflow syntax. Each property defines an input with its type and description.",
              "additionalProperties": {
                "type": "object",
                "properties": {
                  "type": {
                    "type": "string",
                    "enum": ["string", "number", "boolean", "array", "object"],
                    "default": "string",
                    "description": "The JSON schema type of the input parameter."
                  },
                  "description": {
                    "type": "string",
                    "description": "Description of the input parameter."
                  },
                  "required": {
                    "type": "boolean",
                    "default": false,
                    "description": "Whether this input is required."
                  },
                  "default": {
                    "description": "Default value for the input parameter."
                  }
                },
                "additionalProperties": false
              }
            },
            "script": {
              "type": "string",
              "description": "JavaScript implementation (CommonJS format). The script receives input parameters as a JSON object and should return a result. Cannot be used together with 'run', 'py', or 'go'."
            },
            "run": {
              "type": "string",
              "description": "Shell script implementation. The script receives input parameters as environment variables (JSON-encoded for complex types). Cannot be used together with 'script', 'py', or 'go'."
            },
            "py": {
              "type": "string",
              "description": "Python script implementation. The script receives input parameters as environment variables (INPUT_* prefix, uppercased). Cannot be used together with 'script', 'run', or 'go'."
            },
            "go": {
              "type": "string",
              "description": "Go script implementation. The script is executed using 'go run' and receives input parameters as JSON via stdin. Cannot be used together with 'script', 'run', or 'py'."
            },
            "env": {
              "type": "object",
              "description": "Environment variables to pass to the tool, typically for secrets. Use ${{ secrets.NAME }} syntax.",
              "additionalProperties": {
                "type": "string"
              },
              "examples": [
                {
                  "GH_TOKEN": "${{ secrets.GITHUB_TOKEN }}",
                  "API_KEY": "${{ secrets.MY_API_KEY }}"
                }
              ]
            },
            "timeout": {
              "type": "integer",
              "description": "Timeout in seconds for tool execution. Default is 60 seconds. Applies to shell (run) and Python (py) tools.",
              "default": 60,
              "minimum": 1,
              "examples": [30, 60, 120, 300]
            }
          },
          "additionalProperties": false,
          "oneOf": [
            {
              "required": ["script"],
              "not": {
                "anyOf": [
                  {
                    "required": ["run"]
                  },
                  {
                    "required": ["py"]
                  },
                  {
                    "required": ["go"]
                  }
                ]
              }
            },
            {
              "required": ["run"],
              "not": {
                "anyOf": [
                  {
                    "required": ["script"]
                  },
                  {
                    "required": ["py"]
                  },
                  {
                    "required": ["go"]
                  }
                ]
              }
            },
            {
              "required": ["py"],
              "not": {
                "anyOf": [
                  {
                    "required": ["script"]
                  },
                  {
                    "required": ["run"]
                  },
                  {
                    "required": ["go"]
                  }
                ]
              }
            },
            {
              "required": ["go"],
              "not": {
                "anyOf": [
                  {
                    "required": ["script"]
                  },
                  {
                    "required": ["run"]
                  },
                  {
                    "required": ["py"]
                  }
                ]
              }
            }
          ]
        }
      },
      "examples": [
        {
          "search-issues": {
            "description": "Search GitHub issues using the GitHub API",
            "inputs": {
              "query": {
                "type": "string",
                "description": "Search query for issues",
                "required": true
              },
              "limit": {
                "type": "number",
                "description": "Maximum number of results",
                "default": 10
              }
            },
            "script": "const { Octokit } = require('@octokit/rest');\nconst octokit = new Octokit({ auth: process.env.GH_TOKEN });\nconst result = await octokit.search.issuesAndPullRequests({ q: inputs.query, per_page: inputs.limit });\nreturn result.data.items;",
            "env": {
              "GH_TOKEN": "${{ secrets.GITHUB_TOKEN }}"
            }
          }
        },
        {
          "run-linter": {
            "description": "Run a custom linter on the codebase",
            "inputs": {
              "path": {
                "type": "string",
                "description": "Path to lint",
                "default": "."
              }
            },
            "run": "eslint $INPUT_PATH --format json",
            "env": {
              "INPUT_PATH": "${{ inputs.path }}"
            }
          }
        }
      ],
      "additionalProperties": false
    },
    "runtimes": {
      "type": "object",
      "description": "Runtime environment version overrides. Allows customizing runtime versions (e.g., Node.js, Python) or defining new runtimes. Runtimes from imported shared workflows are also merged.",
      "patternProperties": {
        "^[a-z][a-z0-9-]*$": {
          "type": "object",
          "description": "Runtime configuration object identified by runtime ID (e.g., 'node', 'python', 'go')",
          "properties": {
            "version": {
              "type": ["string", "number"],
              "description": "Runtime version as a string (e.g., '22', '3.12', 'latest') or number (e.g., 22, 3.12). Numeric values are automatically converted to strings at runtime.",
              "examples": ["22", "3.12", "latest", 22, 3.12]
            },
            "action-repo": {
              "type": "string",
              "description": "GitHub Actions repository for setting up the runtime (e.g., 'actions/setup-node', 'custom/setup-runtime'). Overrides the default setup action."
            },
            "action-version": {
              "type": "string",
